import * as d3 from 'd3'
import { MakeLogicType, actions, afterMount, connect, kea, key, listeners, path, props, reducers } from 'kea'
import { subscriptions } from 'kea-subscriptions'

import { GoalLine } from '~/queries/schema/schema-general'

import type { ChartSettings, DataVisualizationNode } from '../../schema/schema-general'
import { dataVisualizationLogic } from './dataVisualizationLogic'
import type { AxisSeries } from './dataVisualizationLogic'

export interface DisplayLogicProps {
    key: string
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface displayLogicValues {
    chartSettings: ChartSettings // dataVisualizationLogic
    query: DataVisualizationNode // dataVisualizationLogic
    yData: AxisSeries<number | null>[] // dataVisualizationLogic
    goalLines: GoalLine[]
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface displayLogicActions {
    _setQuery: (node: DataVisualizationNode) => {
        node: DataVisualizationNode
    } // dataVisualizationLogic
    setQuery: (setter: (node: DataVisualizationNode) => DataVisualizationNode) => {
        setter: (node: DataVisualizationNode) => DataVisualizationNode
    } // dataVisualizationLogic
    updateChartSettings: (settings: ChartSettings) => {
        settings: ChartSettings
    } // dataVisualizationLogic
    addGoalLine: () => {
        yData: AxisSeries<number | null>[]
    }
    removeGoalLine: (goalLineIndex: number) => {
        goalLineIndex: number
    }
    setGoalLines: (goalLines: GoalLine[]) => {
        goalLines: GoalLine[]
    }
    updateGoalLine: (
        goalLineIndex: number,
        key: string,
        value: boolean | number | string
    ) => {
        goalLineIndex: number
        key: string
        value: boolean | number | string
    }
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface displayLogicMeta {
    key: string
}

export type displayLogicType = MakeLogicType<
    displayLogicValues,
    displayLogicActions,
    DisplayLogicProps,
    displayLogicMeta
>

export const displayLogic = kea<displayLogicType>([
    key((props) => props.key),
    path(['queries', 'nodes', 'DataVisualization', 'displayLogic']),
    props({ key: '' } as DisplayLogicProps),
    connect(() => ({
        values: [dataVisualizationLogic, ['yData', 'query', 'chartSettings']],
        actions: [dataVisualizationLogic, ['setQuery', 'updateChartSettings', '_setQuery']],
    })),
    actions(({ values }) => ({
        addGoalLine: () => ({ yData: values.yData }),
        updateGoalLine: (goalLineIndex: number, key: string, value: string | number | boolean) => ({
            goalLineIndex,
            key,
            value,
        }),
        removeGoalLine: (goalLineIndex: number) => ({ goalLineIndex }),
        setGoalLines: (goalLines: GoalLine[]) => ({ goalLines }),
    })),
    reducers({
        goalLines: [
            [] as GoalLine[],
            {
                addGoalLine: (state, { yData }) => {
                    const yDataFlat =
                        yData?.flatMap((n) => n.data).filter((value): value is number => value !== null) ?? []
                    const yDataAvg = Math.round(d3.mean(yDataFlat) ?? 0)

                    return [
                        ...state,
                        {
                            label: 'Q4 Goal',
                            value: yDataAvg ?? 0,
                            displayLabel: true,
                        },
                    ]
                },
                removeGoalLine: (state, { goalLineIndex }) => {
                    return state.filter((_, i) => i !== goalLineIndex)
                },
                updateGoalLine: (state, { goalLineIndex, key, value }) => {
                    return state.map((line, i) => (i === goalLineIndex ? { ...line, [key]: value } : line))
                },
                setGoalLines: (_state, { goalLines }) => {
                    return goalLines
                },
            },
        ],
    }),
    listeners(({ actions }) => ({
        _setQuery: ({ node }) => {
            actions.setGoalLines(node.chartSettings?.goalLines ?? [])
        },
    })),
    afterMount(({ values, actions }) => {
        const chartSettings = values.query.chartSettings

        if (chartSettings?.goalLines) {
            actions.setGoalLines(chartSettings.goalLines)
        }
    }),
    subscriptions(({ actions, values }) => ({
        goalLines: (value: GoalLine[]) => {
            const currentGoalLines = values.chartSettings?.goalLines ?? []
            const newGoalLines = value.length > 0 ? value : []

            if (JSON.stringify(currentGoalLines) === JSON.stringify(newGoalLines)) {
                return
            }

            actions.updateChartSettings({ goalLines: value.length > 0 ? value : undefined })
        },
    })),
])
